<template>
  <div class="container px-4 py-10 mx-auto overflow-y-auto">
    <cart-detail ref="cart_detail" v-show="status == 'detail'" />
    <cart-list
      ref="cart_list"
      v-show="status == 'list'"
      @showdetail="showdetail"
    />
  </div>
</template>
<script>
import CartList from "./List.vue";
import CartDetail from "./Detail.vue";

export default {
  name: "CartPage",
  components: { CartDetail, CartList },
  data() {
    return {
      status: "list",
    };
  },
  methods: {
    showdetail() {
      this.status = "detail";
    },
  },
};
</script>
